let _ticketModal;function openTicketModal(){_ticketModal&&(document.getElementById("ticketTitle").value="",document.getElementById("ticketDescription").value="",document.getElementById("ticketCategory").value="Bug",document.getElementById("ticketSeverity").value="Medium",document.getElementById("ticketTitle").classList.remove("is-invalid"),_ticketModal.show(),setTimeout(function(){document.getElementById("ticketTitle").focus()},300))}async function submitTicket(){var e=document.getElementById("ticketTitle").value.trim();if(e){document.getElementById("ticketTitle").classList.remove("is-invalid");var t=document.getElementById("ticketSubmitBtn");t.disabled=!0,t.innerHTML='<i class="fas fa-spinner fa-spin me-1"></i> Submitting...';try{var i=await fetch("/casehub/api/tickets/submit",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({title:e,description:document.getElementById("ticketDescription").value.trim(),category:document.getElementById("ticketCategory").value,severity:document.getElementById("ticketSeverity").value,page_url:window.location.href,browser:navigator.userAgent,version:document.querySelector(".top-bar .text-muted")?document.querySelector(".top-bar .text-muted").textContent.replace("CaseHub ",""):"",environment:screen.width+"x"+screen.height+" | "+navigator.language})}),o=await i.json();_ticketModal&&_ticketModal.hide(),o.success?"function"==typeof showToast?showToast("success","Ticket submitted! It will be reviewed shortly."):alert("Ticket submitted! It will be reviewed shortly."):"function"==typeof showToast?showToast("error","Error: "+(o.error||"Try again later")):alert("Error: "+(o.error||"Try again later"))}catch(e){"function"==typeof showToast?showToast("error","Network error: "+e.message):alert("Network error: "+e.message)}finally{t.disabled=!1,t.innerHTML='<i class="fas fa-paper-plane me-1"></i> Submit Ticket'}}else document.getElementById("ticketTitle").classList.add("is-invalid")}document.addEventListener("DOMContentLoaded",function(){const e=document.getElementById("ticketModal");if(e&&e.classList.contains("modal")&&"undefined"!=typeof bootstrap&&bootstrap.Modal)try{_ticketModal=bootstrap.Modal.getOrCreateInstance(e)}catch(e){window.console&&console.warn("ticketModal init failed:",e)}});
